// Keywords for law/criminal classification (invoice detection)
const lawKeywords = ['Invoice', 'invoice', 'INV'];

// Regex: matches PO + optional separator + ("number" OR digits)
const poPattern = /\bpo[\s\-_:]*(number|\d+)/i;

// Regex: detect start of new invoice (common patterns)
const invoiceSplitPattern = /(Invoice Number[:\s]*INV-\d+|\bINV-\d+\b)/gi;

// Process all incoming items
let results = [];

$input.all().forEach(item => {
  const text = item.json.text || '';
  const attachments = item.json.attachments || null;
  const mail_id = item.json.message_id || null;
  const filename = item.json.attachment_metadata?.fileName || null;
  const binary = item.binary || {};

  // Split text keeping markers
  const parts = text.split(invoiceSplitPattern).filter(p => p.trim() !== '');
  const matches = text.match(invoiceSplitPattern) || [];

  let invoices = [];
  let lastMarker = null;

  parts.forEach(part => {
    if (invoiceSplitPattern.test(part)) {
      lastMarker = part.trim(); // new invoice marker
    } else {
      if (lastMarker) {
        invoices.push((lastMarker + ' ' + part).trim());
      }
    }
  });

  invoices.forEach(invText => {
    const lowercaseText = invText.toLowerCase();

    // Skip if no total info
    if (!lowercaseText.includes("total_amount") && !lowercaseText.includes("total")) {
      return;
    }

    // Remove invoice_title if present
    let cleanedText = invText.replace(/"invoice_title"\s*:\s*".*?",?\s*/gi, '');

    // Check for law-related (Invoice detection)
    const isLawRelated = lawKeywords.some(keyword => lowercaseText.includes(keyword));

    // Determine PO status
    let classification = poPattern.test(invText) ? 'po' : 'non po';

    // Check for credit memo in filename
    if (filename && /credit[_\s]?memo/i.test(filename)) {
      classification = classification + " (cm)";
    }

    if (isLawRelated) {
      const filteredBinary = {};
      if (attachments && binary[attachments]) {
        filteredBinary[attachments] = binary[attachments];
      }

      results.push({
        json: {
          related_text: cleanedText,
          attachments: attachments,
          filename: filename,
          po_status: classification,
          mail_Id: mail_id
        },
        binary: filteredBinary
      });
    }
  });
});

return results;
